#!/usr/bin/env bash
# edtech-saas-gtm-go-to-market.sh — EdTech SaaS GTM（Go-to-Market） SOP walkthrough for 教育SaaS.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="教育SaaS"
WORKFLOW="EdTech SaaS GTM（Go-to-Market）"

usage() {
  cat <<EOF
edtech-saas-gtm-go-to-market.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./edtech-saas-gtm-go-to-market.sh             # interactive
  ./edtech-saas-gtm-go-to-market.sh --dry-run
  ./edtech-saas-gtm-go-to-market.sh --json
  ./edtech-saas-gtm-go-to-market.sh --explain
  ./edtech-saas-gtm-go-to-market.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "EdTech SaaS GTM（Go-to-Market）" 工作流。

入门 SOP 共 7 步, 失败模式自检 3 项。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "ICP 定义: 明确理想客户画像（机构类型/规模/技术成熟度/预算周期），选定1-2个细分市场 [T03-S014]"
  "Pilot 设计: 选5-10个目标客户做免费/低价pilot，设定成功指标（使用频率/具体学习结果）[T03-S014]"
  "冠军培育: 在pilot机构内找到\"内部冠军\"（热情的教师/IT主任），提供白手套服务 [T03-S014]"
  "价值验证: 收集量化证据（数据对比/学生成果），撰写Case Study，获取推荐信 [T03-S014]"
  "采购流程导航: 理解教育机构采购节奏（K-12: 1-3月评估/6-7月决策；高校: RFP周期18个月），提前布局 [T03-S001]"
  "扩张: 通过冠军推动机构内部扩张（从一个学院→全校），同类机构横向复制 [T03-S014]"
  "客户成功: 配置CSM，设季度业务回顾，NPS追踪，主动识别扩张机会和流失风险 [T03-S014]"
)
declare -a FAILURE_MODES=(
  "Pilot太广（选太多机构），无法提供白手套服务，pilot失败率高"
  "忽视教育采购时间线，产品发布时间与采购窗口错位"
  "过度依赖产品自增长（PLG）在高校大客户中行不通，需要企业销售配合"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "edtech-saas-gtm-go-to-market-walkthrough"
fi
